#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

static std::vector<std::vector<double>> mat(cJSON* j){
    std::vector<std::vector<double>> m;
    cJSON* row; cJSON_ArrayForEach(row, j){
        std::vector<double> r; cJSON* e;
        cJSON_ArrayForEach(e, row) r.push_back(e->valuedouble);
        m.push_back(r);
    }
    return m;
}
static std::vector<double> vec(cJSON* j){
    std::vector<double> v; cJSON* e;
    cJSON_ArrayForEach(e, j) v.push_back(e->valuedouble);
    return v;
}
static std::vector<double> linear(const std::vector<std::vector<double>>& W,
                                  const std::vector<double>& b,
                                  const std::vector<double>& x){
    std::vector<double> out(W.size());
    for(size_t i=0;i<W.size();++i){
        double s=b[i];
        for(size_t k=0;k<x.size();++k) s+=W[i][k]*x[k];
        out[i]=s;
    }
    return out;
}
static void relu(std::vector<double>& v){ for(double& e:v) if(e<0) e=0; }

int main(int argc,char**argv){
    if(argc<3){ fprintf(stderr,"usage: %s weights.json image.png\n",argv[0]); return 1; }
    // read weights.json
    FILE* f=fopen(argv[1],"rb");
    if(!f){ fprintf(stderr,"cannot open weights\n"); return 1; }
    fseek(f,0,SEEK_END); long n=ftell(f); fseek(f,0,SEEK_SET);
    std::string buf; buf.resize(n);
    if(fread(&buf[0],1,n,f)!=(size_t)n){ fclose(f); return 1; }
    fclose(f);
    cJSON* root=cJSON_Parse(buf.c_str());
    if(!root){ fprintf(stderr,"bad json\n"); return 1; }
    auto W1=mat(cJSON_GetObjectItem(root,"input_layer.weight"));
    auto b1=vec(cJSON_GetObjectItem(root,"input_layer.bias"));
    auto W2=mat(cJSON_GetObjectItem(root,"hidden_layer.weight"));
    auto b2=vec(cJSON_GetObjectItem(root,"hidden_layer.bias"));
    auto W3=mat(cJSON_GetObjectItem(root,"output_layer.weight"));
    auto b3=vec(cJSON_GetObjectItem(root,"output_layer.bias"));

    // decode png as grayscale
    std::vector<unsigned char> img; unsigned w,h;
    unsigned err=lodepng::decode(img,w,h,argv[2],LCT_GREY,8);
    if(err){ fprintf(stderr,"png err %s\n",lodepng_error_text(err)); return 1; }
    std::vector<double> x(w*h);
    for(size_t i=0;i<x.size();++i) x[i]=img[i]/255.0;

    auto a1=linear(W1,b1,x); relu(a1);
    auto a2=linear(W2,b2,a1); relu(a2);
    auto out=linear(W3,b3,a2);
    int best=0; for(size_t i=1;i<out.size();++i) if(out[i]>out[best]) best=(int)i;
    printf("%d\n",best);
    cJSON_Delete(root);
    return 0;
}

